using System.Collections.Generic;\nusing UnityEngine;\n\npublic class TreeManager : MonoBehaviour {\n    public enum TreeType { SMALL, MEDIUM, LARGE, ANCIENT }\n    private Dictionary<TreeType, GameObject> treeModels;\n    private TreeType selectedTree;\n\n    void Start() {\n        LoadTreeModels();\n    }\n\n    private void LoadTreeModels() {\n        // Load tree models here\n        treeModels = new Dictionary<TreeType, GameObject> {\n            { TreeType.SMALL, Resources.Load<GameObject>("Trees/SmallTree") },\n            { TreeType.MEDIUM, Resources.Load<GameObject>("Trees/MediumTree") },\n            { TreeType.LARGE, Resources.Load<GameObject>("Trees/LargeTree") },\n            { TreeType.ANCIENT, Resources.Load<GameObject>("Trees/AncientTree") }\n        };\n    }\n\n    public void SelectTree(TreeType treeType) {\n        selectedTree = treeType;\n        // Additional logic for selecting tree if needed\n    }\n\n    public TreeType GetSelectedTree() {\n        return selectedTree;\n    }\n\n    public string GetTreeInfo(TreeType treeType) {\n        switch(treeType) {\n            case TreeType.SMALL: return "A small tree suitable for parks.";\n            case TreeType.MEDIUM: return "A medium-sized tree often found in forests.";\n            case TreeType.LARGE: return "A large tree providing ample shade.";\n            case TreeType.ANCIENT: return "An ancient tree with historic significance.";\n            default: return "Unknown tree type.";\n        }\n    }\n}